function.body:
TYPE RECORD IS REF CURSOR;
  Cur_Params RECORD;
  Cur_Invoice RECORD;
  v_Record_ID VARCHAR2(32);
  v_Client_ID VARCHAR2(32);
  v_Org_ID VARCHAR2(32);
  v_User_ID VARCHAR2(32) ;
  v_ResultStr VARCHAR2(2000) := '';  
  v_docstatus  VARCHAR2(160):='';
  v_issotrx  VARCHAR2(160):='';
  v_em_eei_description  VARCHAR2(160):='';
  p_docaction VARCHAR2(160):='';
  v_Description VARCHAR2(2000) := '';  
  v_FinalDescription VARCHAR2(2000) := '';  
  v_Count NUMBER:=0;
  Cur_InvoiceLine RECORD;

BEGIN

  FOR Cur_Params IN (
    SELECT *
    FROM ad_ep_instance_para 
    WHERE ad_ep_instance_id = pinstance_id
    ) LOOP
    IF (cur_params.parametername LIKE 'DocAction') THEN
      p_docaction := Cur_Params.p_string;
    ELSIF (cur_params.parametername LIKE 'Record_ID') THEN
      v_Record_ID := cur_params.p_string;
    END IF;
  END LOOP;

	SELECT docstatus,issotrx,trim(trailing '
' from (trim(COALESCE(em_eei_description,''))))
		INTO v_docstatus,v_issotrx,v_em_eei_description 
	from c_invoice  where  c_invoice_id =v_Record_ID;

  --VALIDO QUE SEA FACTURA DE VENTA
	IF(v_issotrx='Y')THEN
		IF(v_docstatus ='CO' or v_docstatus ='DR') THEN
			For Cur_invoiceline In(
				SELECT ORD.documentno ,PAT.Name_Lastname
				FROM c_invoice  INV 
					join c_invoiceline INVL on INVL.c_invoice_id = INV.c_invoice_id
					join c_orderline ORDL on ORDL.c_orderline_id = INVL.c_orderline_id
					join c_order ORD on ORD.c_order_id = ORDL.c_order_id
					join slab_patient PAT on PAT.slab_patient_id=  ORD.EM_Slab_Patient_ID
				WHERE INV.c_invoice_id = v_Record_ID 
				GROUP BY ORD.documentno,PAT.Name_Lastname
			)
			Loop

			v_Description = Cur_invoiceline.documentno||'
'|| Cur_invoiceline.Name_Lastname;
			END LOOP;

			IF(v_Description is not null or v_Description<>'')THEN
				IF(v_docstatus='CO')THEN
						IF(v_em_eei_description is null or v_em_eei_description ='')THEN
							v_FinalDescription:=v_Description;
						ELSE
							v_FinalDescription:=v_em_eei_description||'
'||v_Description;
						END IF;
						UPDATE c_invoice  SET 
							em_eei_description  = v_FinalDescription
						WHERE c_invoice_id = v_Record_ID ;
				ELSIF(v_docstatus='DR')THEN

					v_FinalDescription:=replace(v_em_eei_description, v_Description, '');

				END IF;

				UPDATE c_invoice  SET 
					em_eei_description  = v_FinalDescription
				WHERE c_invoice_id = v_Record_ID ;

			END IF;


		END IF;
	END IF;


EXCEPTION
WHEN OTHERS THEN
  DBMS_OUTPUT.PUT_LINE( v_ResultStr);
  RAISE;
END SIUDD_UPDATE_INVDESCRIPTION
